160	            if (!prior) return;
161	            if (prior.status === next.status) return;
162	            const nextStatus = next.status;
163	            setRows((cur) =>
164	              cur.map((r) => (r.id === next.id ? { ...r, status: nextStatus } : r)),
165	            );
166	          },
167	        )
168	        .subscribe();
169	    });
