78	  return (
79	    <View style={styles.segmentRow} accessibilityRole="tablist">
80	      {SEGMENTS.map((s) => (
81	        <SegmentButton
82	          key={s.key}
83	          label={s.label}
84	          selected={active === s.key}
85	          onPress={() => onChange(s.key)}
86	          testID={`segment-${s.key}`}
87	        />
88	      ))}
89	    </View>
90	  );
91	}
