102	  const textColor = selected ? colors.primaryDeep : colors.ink;
103	  return (
104	    <Pressable
105	      onPress={onPress}
106	      accessibilityRole="tab"
107	      accessibilityState={{ selected }}
108	      accessibilityLabel={label}
109	      style={[styles.segment, { backgroundColor: bg }, shadows.hard]}
